<?php
require __DIR__ . '/config.php';

$page = $_GET['page'] ?? 'home';
function layout_start(string $title): void { ?>
<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title><?=e($title)?> · <?=APP_NAME?></title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css" rel="stylesheet"><link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.3/font/bootstrap-icons.css" rel="stylesheet"><link href="style.css" rel="stylesheet"></head><body>
<nav class="navbar navbar-expand-lg navbar-dark"><div class="container"><a class="navbar-brand" href="?"><i class="bi bi-translate me-2"></i>Kare Kare</a><button class="navbar-toggler" data-bs-toggle="collapse" data-bs-target="#nav"><span class="navbar-toggler-icon"></span></button><div class="collapse navbar-collapse" id="nav"><ul class="navbar-nav ms-auto align-items-lg-center gap-lg-1"><li class="nav-item"><a class="nav-link" href="?">Translate</a></li><?php if (user()): ?><li class="nav-item"><a class="nav-link" href="?page=contribute">Contribute</a></li><?php if(is_admin()): ?><li class="nav-item"><a class="nav-link" href="?page=admin">Dashboard</a></li><?php endif ?><li class="nav-item"><a class="nav-link" href="?page=profile">Hi, <?=e(user()['username'])?></a></li><li class="nav-item"><a class="btn btn-sm btn-outline-light ms-lg-2" href="?page=logout">Log out</a></li><?php else: ?><li class="nav-item"><a class="nav-link" href="?page=login">Sign in</a></li><li class="nav-item"><a class="btn btn-sm btn-light ms-lg-2" href="?page=register">Join as contributor</a></li><?php endif ?></ul></div></div></nav>
