function layout_end(): void { ?></main><footer class="py-5 text-center text-secondary small">© <?=date('Y')?> Kare Kare · Hausa–English Dictionary</footer><script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/js/bootstrap.bundle.min.js"></script></body></html><?php }

if ($page === 'logout') { session_destroy(); session_start(); flash('You have been signed out.'); redirect(); }
if ($page === 'login' && $_SERVER['REQUEST_METHOD'] === 'POST') { verify_csrf(); $identity=trim($_POST['identity']??''); $q=db()->prepare('SELECT * FROM users WHERE username=? OR email=? LIMIT 1'); $q->execute([$identity,$identity]); $u=$q->fetch(); $ok=$u && password_verify($_POST['password']??'', $u['password']); db()->prepare('INSERT INTO login_history (user_id,username,ip_address,success) VALUES (?,?,?,?)')->execute([$u['id']??null,$identity,$_SERVER['REMOTE_ADDR']??null,(int)$ok]); if(!$ok){flash('Incorrect username/email or password.','danger');redirect('?page=login');} $_SESSION['user']=['id'=>(int)$u['id'],'username'=>$u['username'],'role'=>$u['role'],'email'=>$u['email']]; db()->prepare('UPDATE users SET last_login_at=NOW() WHERE id=?')->execute([$u['id']]); log_activity('Signed in'); flash($u['must_change_password']?'Please change the default password now.':'Welcome back, '.$u['username'].'!'); redirect($u['must_change_password']?'?page=profile':'?'); }
if ($page === 'register' && $_SERVER['REQUEST_METHOD'] === 'POST') { verify_csrf(); $name=trim($_POST['username']??'');$email=filter_var($_POST['email']??'',FILTER_VALIDATE_EMAIL);$pass=$_POST['password']??''; if(!preg_match('/^[A-Za-z0-9_]{3,60}$/',$name)||!$email||strlen($pass)<8){flash('Use a valid username, email, and an 8+ character password.','danger');redirect('?page=register');} try {db()->prepare("INSERT INTO users (username,email,password) VALUES (?,?,?)")->execute([$name,$email,password_hash($pass,PASSWORD_DEFAULT)]);flash('Account created. Please sign in.');redirect('?page=login');}catch(PDOException $e){flash('That username or email is already in use.','danger');redirect('?page=register');} }
if ($page === 'profile' && $_SERVER['REQUEST_METHOD'] === 'POST') { require_login();verify_csrf();$pass=$_POST['new_password']??'';if(strlen($pass)<8){flash('Password must have at least 8 characters.','danger');redirect('?page=profile');} db()->prepare('UPDATE users SET password=?,must_change_password=0 WHERE id=?')->execute([password_hash($pass,PASSWORD_DEFAULT),user()['id']]);log_activity('Changed password');flash('Password updated.');redirect('?page=profile'); }
if ($page === 'contribute' && $_SERVER['REQUEST_METHOD'] === 'POST') { require_login();verify_csrf();$hausa=trim($_POST['hausa_word']??'');$english=trim($_POST['english_meaning']??'');$example=trim($_POST['example_sentence']??'');if(!$hausa||!$english){flash('Hausa word and English meaning are required.','danger');redirect('?page=contribute');}$exists=db()->prepare('SELECT id FROM translations WHERE LOWER(hausa_word)=LOWER(?)');$exists->execute([$hausa]);if($exists->fetch()){flash('This word already exists in the public dictionary.','warning');redirect('?page=contribute');}db()->prepare('INSERT INTO contributions (hausa_word,english_meaning,example_sentence,contributor_id) VALUES (?,?,?,?)')->execute([$hausa,$english,$example?:null,user()['id']]);log_activity('Submitted contribution',$hausa);flash('Thank you — your contribution is waiting for administrator review.');redirect('?page=contribute'); }
if ($page === 'admin_action' && $_SERVER['REQUEST_METHOD'] === 'POST') { require_admin();verify_csrf();$action=$_POST['action']??'';$id=(int)($_POST['id']??0); if($action==='review'){ $c=db()->prepare('SELECT * FROM contributions WHERE id=? AND status="pending"');$c->execute([$id]);$row=$c->fetch();if($row){$status=$_POST['decision']==='approve'?'approved':'rejected';db()->prepare('UPDATE contributions SET status=?,reviewer_id=?,review_note=?,reviewed_at=NOW() WHERE id=?')->execute([$status,user()['id'],trim($_POST['note']??'')?:null,$id]);if($status==='approved'){try{db()->prepare('INSERT INTO translations (hausa_word,english_meaning,example_sentence,created_by) VALUES (?,?,?,?)')->execute([$row['hausa_word'],$row['english_meaning'],$row['example_sentence'],user()['id']]);}catch(PDOException $e){flash('Contribution reviewed, but the word is already in the dictionary.','warning');}}log_activity(ucfirst($status).' contribution',$row['hausa_word']);flash('Contribution '.$status.'.');}} elseif($action==='delete_translation'){db()->prepare('DELETE FROM translations WHERE id=?')->execute([$id]);log_activity('Deleted translation',(string)$id);flash('Translation deleted.');} redirect('?page=admin'); }

if ($page === 'export') { require_admin(); if (!class_exists('PhpOffice\\PhpSpreadsheet\\Spreadsheet')) { flash('Install PhpSpreadsheet with Composer to enable Excel export.','warning'); redirect('?page=admin'); } $sheet=new \PhpOffice\PhpSpreadsheet\Spreadsheet();$ws=$sheet->getActiveSheet();$ws->fromArray(['Hausa Word','English Meaning','Example Sentence'],null,'A1');$rows=db()->query('SELECT hausa_word,english_meaning,example_sentence FROM translations ORDER BY hausa_word')->fetchAll(PDO::FETCH_NUM);$ws->fromArray($rows,null,'A2');header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="kare-kare-dictionary.xlsx"');(new \PhpOffice\PhpSpreadsheet\Writer\Xlsx($sheet))->save('php://output');exit; }
if ($page === 'import' && $_SERVER['REQUEST_METHOD'] === 'POST') { require_admin();verify_csrf(); if(!class_exists('PhpOffice\\PhpSpreadsheet\\IOFactory')){flash('PhpSpreadsheet is not installed. Run composer require phpoffice/phpspreadsheet.','warning');redirect('?page=admin');}if(($_FILES['dataset']['error']??1)!==UPLOAD_ERR_OK||strtolower(pathinfo($_FILES['dataset']['name'],PATHINFO_EXTENSION))!=='xlsx'){flash('Choose a valid .xlsx file.','danger');redirect('?page=admin');}$rows=\PhpOffice\PhpSpreadsheet\IOFactory::load($_FILES['dataset']['tmp_name'])->getActiveSheet()->toArray();$count=0;foreach(array_slice($rows,1) as $r){$h=trim((string)($r[0]??''));$m=trim((string)($r[1]??''));if($h&&$m){db()->prepare('INSERT INTO translations (hausa_word,english_meaning,example_sentence,created_by) VALUES (?,?,?,?) ON DUPLICATE KEY UPDATE english_meaning=VALUES(english_meaning),example_sentence=VALUES(example_sentence)')->execute([$h,$m,trim((string)($r[2]??''))?:null,user()['id']]);$count++;}}log_activity('Imported dataset',$count.' rows');flash("Imported or updated $count translations.");redirect('?page=admin'); }

if ($page === 'login' || $page === 'register') { $reg=$page==='register'; layout_start($reg?'Register':'Sign in'); ?>
