if ($page === 'profile') { require_login();layout_start('Profile'); ?><div class="container py-5" style="max-width:700px"><h1 class="section-title mb-4">Your profile</h1><div class="card p-4"><h2 class="h5"><?=e(user()['username'])?> <span class="badge text-bg-success"><?=e(user()['role'])?></span></h2><hr><h3 class="h5">Change password</h3><form method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><input required minlength="8" type="password" class="form-control my-3" name="new_password" placeholder="New password"><button class="btn btn-primary">Update password</button></form></div></div><?php layout_end();exit; }
if ($page === 'contribute') { require_login();layout_start('Contribute'); ?><div class="container py-5" style="max-width:800px"><div class="card p-4 p-md-5"><span class="badge badge-soft">Contributor space</span><h1 class="section-title mt-3">Add a Hausa translation</h1><p class="text-secondary">Your submission is reviewed before public release.</p><form method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><div class="mb-3"><label class="form-label">Hausa word or phrase *</label><input required maxlength="255" class="form-control" name="hausa_word"></div><div class="mb-3"><label class="form-label">English meaning *</label><textarea required class="form-control" name="english_meaning" rows="3"></textarea></div><div class="mb-4"><label class="form-label">Example sentence (optional)</label><textarea class="form-control" name="example_sentence" rows="2"></textarea></div><button class="btn btn-primary">Submit for review</button></form></div></div><?php layout_end();exit; }
if ($page === 'admin') { require_admin(); $stats=['Words'=>(int)db()->query('SELECT COUNT(*) FROM translations')->fetchColumn(),'Contributors'=>(int)db()->query("SELECT COUNT(*) FROM users WHERE role='contributor'")->fetchColumn(),'Pending'=>(int)db()->query("SELECT COUNT(*) FROM contributions WHERE status='pending'")->fetchColumn(),'Searches'=>(int)db()->query('SELECT COUNT(*) FROM search_history')->fetchColumn()];$pending=db()->query("SELECT c.*,u.username FROM contributions c JOIN users u ON u.id=c.contributor_id WHERE c.status='pending' ORDER BY c.created_at")->fetchAll();layout_start('Admin dashboard'); ?><div class="container py-5"><div class="d-flex justify-content-between align-items-center mb-4"><div><span class="text-success fw-semibold">Administration</span><h1 class="section-title mb-0">Dictionary dashboard</h1></div><a class="btn btn-outline-success" href="?page=export">Export Excel</a></div><div class="row g-3 mb-5"><?php foreach($stats as $label=>$num):?><div class="col-6 col-lg-3"><div class="card stat"><div class="text-secondary small text-uppercase"><?=e($label)?></div><div class="number"><?=$num?></div></div></div><?php endforeach?></div><div class="row g-4"><div class="col-lg-4"><div class="card p-4"><h2 class="h5">Import dataset</h2><p class="small text-secondary">Upload .xlsx. Existing words update automatically.</p><form method="post" action="?page=import" enctype="multipart/form-data"><input type="hidden" name="csrf" value="<?=csrf()?>"><input required accept=".xlsx" class="form-control mb-3" type="file" name="dataset"><button class="btn btn-primary w-100">Import Excel</button></form></div></div><div class="col-lg-8"><div class="card p-4"><h2 class="h5">Pending contributions <span class="badge text-bg-warning"><?=$stats['Pending']?></span></h2><?php foreach($pending as $c):?><div class="border rounded-3 p-3 mt-3"><strong><?=e($c['hausa_word'])?></strong> <span class="text-secondary">— <?=e($c['english_meaning'])?></span><small class="d-block text-secondary">by <?=e($c['username'])?></small><form method="post" action="?page=admin_action" class="d-flex gap-2 mt-2"><input type="hidden" name="csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="review"><input type="hidden" name="id" value="<?=$c['id']?>"><button name="decision" value="approve" class="btn btn-sm btn-success">Approve</button><button name="decision" value="reject" class="btn btn-sm btn-outline-danger">Reject</button></form></div><?php endforeach;if(!$pending):?><p class="text-secondary mb-0">Nothing waiting for review.</p><?php endif?></div></div></div></div><?php layout_end();exit; }
if ($page === 'home') { $term=trim($_GET['q']??'');$results=[];if($term!==''){$q=db()->prepare('SELECT * FROM translations WHERE hausa_word LIKE ? OR english_meaning LIKE ? ORDER BY CASE WHEN LOWER(hausa_word)=LOWER(?) THEN 0 ELSE 1 END, hausa_word LIMIT 12');$like='%'.$term.'%';$q->execute([$like,$like,$term]);$results=$q->fetchAll();db()->prepare('INSERT INTO search_history (user_id,query,result_count) VALUES (?,?,?)')->execute([user()['id']??null,$term,count($results)]);}layout_start('Translate'); ?>
<section class="hero"><div class="container"><span class="badge badge-soft mb-3">Growing community dictionary</span><h1>Hausa words,<br>clearly understood.</h1><p>Find English meanings instantly and help preserve a living language, one verified word at a time.</p></div></section><div class="container search-panel"><div class="card search-card"><form class="row g-2" method="get"><div class="col-md"><label class="visually-hidden">Hausa word or phrase</label><input autofocus class="form-control form-control-lg" name="q" value="<?=e($term)?>" placeholder="Enter a Hausa word or phrase…"></div><div class="col-md-auto"><button class="btn btn-primary btn-lg w-100"><i class="bi bi-search me-2"></i>Translate</button></div></form></div><?php if($term!==''): ?><section class="py-5"><div class="d-flex justify-content-between align-items-center mb-3"><h2 class="section-title h3 mb-0">Results for “<?=e($term)?>”</h2><span class="text-secondary"><?=count($results)?> found</span></div><?php if($results): foreach($results as $r): ?><article class="card word-card mb-3 p-4"><div class="d-flex justify-content-between gap-3"><div><div class="text-secondary small text-uppercase fw-bold mb-1">Hausa</div><h3 class="h4 mb-3"><?=e($r['hausa_word'])?></h3><div class="text-secondary small text-uppercase fw-bold mb-1">English</div><div class="meaning"><?=e($r['english_meaning'])?></div><?php if($r['example_sentence']): ?><p class="text-secondary mt-3 mb-0"><i class="bi bi-chat-quote me-1"></i><?=e($r['example_sentence'])?></p><?php endif ?></div><i class="bi bi-bookmark text-success fs-4"></i></div></article><?php endforeach;else:?><div class="card p-5 text-center"><i class="bi bi-search-heart fs-1 text-success"></i><h3 class="mt-3">This word was not found.</h3><p class="text-secondary">Would you like to contribute its meaning to the dictionary?</p><a class="btn btn-primary" href="?page=contribute">Contribute a translation</a></div><?php endif ?></section><?php else:?><section class="py-5"><div class="row g-4"><div class="col-md-4"><div class="card p-4 h-100"><i class="bi bi-lightning-charge-fill text-success fs-3"></i><h3 class="h5 mt-3">Fast lookup</h3><p class="text-secondary mb-0">Case-insensitive matching and helpful partial-word results.</p></div></div><div class="col-md-4"><div class="card p-4 h-100"><i class="bi bi-people-fill text-success fs-3"></i><h3 class="h5 mt-3">Community powered</h3><p class="text-secondary mb-0">Contributors grow the dictionary; administrators verify every entry.</p></div></div><div class="col-md-4"><div class="card p-4 h-100"><i class="bi bi-shield-check text-success fs-3"></i><h3 class="h5 mt-3">Trusted meanings</h3><p class="text-secondary mb-0">A review process keeps the public dictionary dependable.</p></div></div></div></section><?php endif ?></div><?php layout_end();exit; }
